CREATE OR REPLACE TABLE `vibe_healthcare_v1`.`digital_health`.`digital_health_rpm_device_reading` (
    `digital_health_rpm_device_reading_id` BIGINT COMMENT 'Surrogate primary key for each RPM device reading event.',
