    `demographics_id` BIGINT COMMENT '',
    `observation_id` BIGINT COMMENT 'FHIR Observation resource ID if this reading was mapped to a FHIR resource.',
    `mpi_record_id` BIGINT COMMENT 'FK to patient MPI record; links the reading to the enterprise patient identity.',
    `digital_health_rpm_alert_threshold_id` BIGINT COMMENT 'Threshold rule evaluated against this reading.',
    `rpm_alert_threshold_id` BIGINT COMMENT 'FK to the alert threshold rule that was evaluated for this reading.',
    `clinician_id` BIGINT COMMENT 'FK to the ordering or supervising clinician for the RPM program.',
    `digital_health_rpm_program_enrollment_id` BIGINT COMMENT 'FK to the RPM program enrollment that authorized this monitoring.',
    `rpm_reviewed_by_clinician_id` BIGINT COMMENT '',
    `alert_acknowledged_by` STRING COMMENT 'Name or user ID of the clinician who acknowledged the alert.',
    `alert_acknowledged_flag` BOOLEAN COMMENT 'Whether the alert generated by this reading has been acknowledged by a clinician.',
    `alert_acknowledged_timestamp` TIMESTAMP COMMENT 'Timestamp when the alert was acknowledged.',
    `alert_severity` STRING COMMENT 'Severity of the triggered alert: low, medium, high, critical.',
    `alert_triggered_flag` BOOLEAN COMMENT 'Indicates whether this reading triggered an alert based on configured thresholds.',
    `context_code` STRING COMMENT 'Clinical context of the reading: fasting, post_meal, post_exercise, resting, sleeping.',
    `created_timestamp` TIMESTAMP COMMENT 'Record creation timestamp in the data lakehouse.',
    `data_quality_flag` BOOLEAN COMMENT 'Whether the reading passed data quality validation.',
    `data_source` STRING COMMENT '',
    `device_identifier` STRING COMMENT 'Unique device identifier (UDI or serial number) of the RPM device that generated the reading.',
    `device_manufacturer` STRING COMMENT 'Manufacturer name of the RPM device.',
    `device_model` STRING COMMENT 'Model name/number of the RPM device.',
    `device_serial_number` STRING COMMENT '',
    `device_type` STRING COMMENT 'Type of device (e.g., pulse_oximeter, glucometer, blood_pressure_cuff, weight_scale, ecg_patch).',
    `diastolic_bp` STRING COMMENT '',
    `diastolic_mmhg` DECIMAL(18,2) COMMENT 'Diastolic blood pressure in mmHg.',
    `ehr_sync_timestamp` TIMESTAMP COMMENT 'Timestamp when the reading was synced to the EHR.',
    `ehr_synced_flag` BOOLEAN COMMENT 'Whether this reading has been synced to the EHR as a clinical observation.',
    `glucose_mg_dl` DECIMAL(18,2) COMMENT 'Blood glucose level in mg/dL; populated when measurement_type=glucose.',
    `heart_rate_bpm` DECIMAL(18,2) COMMENT 'Heart rate in beats per minute; populated when measurement_type=heart_rate.',
    `is_out_of_range_flag` BOOLEAN COMMENT '',
    `loinc_code` STRING COMMENT 'LOINC code corresponding to the measurement type for semantic interoperability.',
    `measurement_type` STRING COMMENT 'Type of measurement: heart_rate, glucose, spo2, weight, blood_pressure_systolic, blood_pressure_diastolic, temperature, respiratory_rate.',
    `measurement_unit` STRING COMMENT 'Unit of measure (e.g., bpm, mg/dL, %, kg, lbs, mmHg, degC, degF, breaths/min).',
    `measurement_value` DECIMAL(18,2) COMMENT 'Numeric value of the measurement in the specified unit.',
    `notes` STRING COMMENT 'Free-text notes from the patient or clinician about this reading.',
    `out_of_range_flag` BOOLEAN COMMENT 'Whether the reading breached an alert threshold.',
    `patient_reported_flag` BOOLEAN COMMENT 'True if the reading was manually entered by the patient rather than auto-transmitted by device.',
    `quality_flag` BOOLEAN COMMENT '',
    `reading_date` DATE COMMENT 'Calendar date of the reading, derived from reading_timestamp for partitioning.',
    `reading_quality_flag` STRING COMMENT 'Quality indicator for the reading: valid, artifact, out_of_range, device_error.',
    `reading_timestamp` TIMESTAMP COMMENT 'Timestamp when the measurement was taken by the device.',
    `reading_type` STRING COMMENT 'Vital type measured (heart_rate, glucose, spo2, weight, blood_pressure).',
    `reading_unit` STRING COMMENT '',
    `reading_value` DECIMAL(18,2) COMMENT '',
    `received_timestamp` TIMESTAMP COMMENT 'Timestamp when the reading was received by the RPM platform.',
    `respiratory_rate_bpm` DECIMAL(18,2) COMMENT 'Respiratory rate in breaths per minute.',
    `reviewed_flag` BOOLEAN COMMENT '',
    `reviewed_timestamp` TIMESTAMP COMMENT '',
    `spo2_percent` DECIMAL(18,2) COMMENT 'Peripheral oxygen saturation percentage; populated when measurement_type=spo2.',
    `systolic_bp` STRING COMMENT '',
    `systolic_mmhg` DECIMAL(18,2) COMMENT 'Systolic blood pressure in mmHg.',
    `temperature_celsius` DECIMAL(18,2) COMMENT 'Body temperature in degrees Celsius.',
    `transmission_method` STRING COMMENT 'How the reading was transmitted: bluetooth, cellular, wifi, manual_entry.',
    `updated_timestamp` TIMESTAMP COMMENT 'Record last-updated timestamp.',
    `weight_kg` DECIMAL(18,2) COMMENT 'Body weight in kilograms; populated when measurement_type=weight.',
    CONSTRAINT pk_digital_health_rpm_device_reading PRIMARY KEY(`digital_health_rpm_device_reading_id`)
) COMMENT 'Stores individual sensor/device readings from Remote Patient Monitoring (RPM) devices including heart rate, glucose, SpO2, and weight. Each row represents a single measurement event transmitted from a patient-connected device.';

