CREATE OR REPLACE TABLE `vibe_healthcare_v1`.`digital_health`.`digital_health_rpm_alert_threshold` (
    `digital_health_rpm_alert_threshold_id` BIGINT COMMENT 'Surrogate primary key for the alert threshold rule.',
    `care_site_id` BIGINT COMMENT 'FK to the care site that owns this threshold configuration.',
    `mpi_record_id` BIGINT COMMENT 'FK to patient MPI record; NULL for program-level defaults.',
    `clinician_id` BIGINT COMMENT 'FK to the clinician who approved this threshold configuration.',
    `rpm_clinician_id` BIGINT COMMENT 'FK to the clinician who configured or approved this threshold.',
    `rpm_created_by_clinician_id` BIGINT COMMENT 'FK to the clinician who created this threshold.',
    `rpm_notify_clinician_id` BIGINT COMMENT '',
    `digital_health_rpm_program_enrollment_id` BIGINT COMMENT 'FK to the specific patient enrollment this threshold applies to; NULL if it is a program-level default.',
    `rpm_set_by_clinician_id` BIGINT COMMENT 'Clinician who configured the threshold.',
    `alert_notification_method` STRING COMMENT 'How alerts are delivered: in_app, sms, email, phone_call, ehr_inbox.',
    `alert_recipient_role` STRING COMMENT 'Role of the alert recipient: care_manager, attending_physician, on_call_nurse.',
    `alert_severity` STRING COMMENT 'Severity assigned when threshold is breached.',
    `alert_severity_lower_critical` STRING COMMENT 'Alert severity label for lower critical breach: critical, high, medium, low.',
    `alert_severity_upper_critical` STRING COMMENT 'Alert severity label for upper critical breach.',
    `clinical_rationale` DECIMAL(18,2) COMMENT 'Free-text clinical rationale for the threshold values.',
    `consecutive_readings_required` STRING COMMENT 'Number of consecutive out-of-range readings required before triggering an alert (reduces false positives).',
    `created_timestamp` TIMESTAMP COMMENT 'Record creation timestamp.',
    `effective_end_date` DATE COMMENT 'Date this threshold rule expires or was superseded.',
    `effective_start_date` DATE COMMENT 'Date this threshold rule became effective.',
    `escalation_rule` STRING COMMENT '',
    `high_critical_value` DECIMAL(18,2) COMMENT '',
    `high_warning_value` DECIMAL(18,2) COMMENT '',
    `is_active` BOOLEAN COMMENT 'Whether this threshold rule is currently active.',
    `is_active_flag` BOOLEAN COMMENT '',
    `loinc_code` STRING COMMENT '',
    `low_critical_value` DECIMAL(18,2) COMMENT '',
    `low_warning_value` DECIMAL(18,2) COMMENT '',
    `lower_critical_value` DECIMAL(18,2) COMMENT 'Lower critical threshold; readings below this value trigger a critical alert.',
    `lower_warning_value` DECIMAL(18,2) COMMENT 'Lower warning threshold; readings below this value trigger a warning alert.',
    `measurement_type` STRING COMMENT 'Measurement type this threshold applies to: heart_rate, glucose, spo2, weight, blood_pressure_systolic, blood_pressure_diastolic, temperature, respiratory_rate.',
    `measurement_unit` STRING COMMENT 'Unit of measure for the threshold values (e.g., bpm, mg/dL, %, kg, mmHg).',
    `reading_type` STRING COMMENT 'Vital type the threshold governs.',
    `suppression_window_minutes` STRING COMMENT 'Minimum minutes between repeated alerts for the same threshold breach to prevent alert fatigue.',
    `threshold_scope` STRING COMMENT 'Scope of the threshold: patient_specific or program_default.',
    `threshold_unit` STRING COMMENT 'Unit of measure for threshold bounds.',
    `unit` STRING COMMENT '',
    `updated_timestamp` TIMESTAMP COMMENT 'Record last-updated timestamp.',
    `upper_critical_value` DECIMAL(18,2) COMMENT 'Upper critical threshold; readings above this value trigger a critical alert.',
    `upper_warning_value` DECIMAL(18,2) COMMENT 'Upper warning threshold; readings above this value trigger a warning alert.',
    CONSTRAINT pk_digital_health_rpm_alert_threshold PRIMARY KEY(`digital_health_rpm_alert_threshold_id`)
) COMMENT 'Defines alert threshold rules for RPM device readings. Each row specifies the upper/lower bounds for a measurement type that, when exceeded, trigger clinical alerts for a patient or program.';

