) COMMENT 'RPM program enrollment and alert thresholds';

CREATE OR REPLACE TABLE `vibe_healthcare_v1`.`digital_health`.`portal_session` (
    `portal_session_id` BIGINT COMMENT 'Primary key for portal_session',
    `care_site_id` BIGINT COMMENT 'Reference to the health system facility or organization context associated with the portal session.',
    `mpi_record_id` BIGINT COMMENT 'Reference to the patient master record (MPI) for whom this portal session was established.',
    `portal_account_id` BIGINT COMMENT 'Reference to the portal user account that authenticated for this session (may be patient, proxy, or caregiver).',
    `previous_portal_session_id` BIGINT COMMENT 'Self-referencing FK on portal_session (previous_portal_session_id)',
    `access_channel` STRING COMMENT 'The interface channel through which the portal was accessed (distinct from device type).',
    `authentication_method` STRING COMMENT 'The mechanism used to authenticate the user at session start.',
    `browser_name` STRING COMMENT 'Web browser name and version used for the portal session, where applicable.',
    `consent_acknowledged_flag` BOOLEAN COMMENT 'Indicates whether required terms-of-use or privacy consent was acknowledged during the session.',
    `device_identifier` STRING COMMENT 'Unique identifier of the device used for the session, supporting trusted-device and fraud-detection workflows.',
    `device_type` STRING COMMENT 'Category of physical device used to access the patient portal.',
    `failed_login_attempts` STRING COMMENT 'Number of failed authentication attempts preceding this successful session, supporting security monitoring.',
    `geo_country` STRING COMMENT 'ISO 3166-1 alpha-3 country code derived from the session source IP for access-pattern monitoring.',
    `geo_region` STRING COMMENT 'State, province, or region inferred from the session source IP location.',
