    `locale_preference` STRING COMMENT 'Language and locale setting (e.g., en-US, es-US) used during the portal session for accessibility and personalization.',
    `login_timestamp` TIMESTAMP COMMENT 'The principal real-world event time when the portal session was initiated via successful authentication.',
    `logout_timestamp` TIMESTAMP COMMENT 'Timestamp when the session was explicitly ended by the user via logout. Nullable for sessions ended by timeout or system.',
    `mfa_completed` BOOLEAN COMMENT 'Indicates whether multi-factor authentication was successfully completed during this session.',
    `operating_system` STRING COMMENT 'Operating system and version reported by the accessing device.',
    `page_view_count` STRING COMMENT 'Number of distinct portal pages or screens viewed during the session, supporting engagement analytics.',
    `phi_accessed_flag` BOOLEAN COMMENT 'Indicates whether Protected Health Information was viewed or accessed during this session, driving HIPAA audit logging.',
    `primary_activity_type` STRING COMMENT 'The dominant functional activity the user performed during the session.',
    `proxy_access_flag` BOOLEAN COMMENT 'Indicates whether the session was conducted by an authorized proxy (e.g., parent, guardian, caregiver) rather than the patient directly.',
    `proxy_relationship` STRING COMMENT 'The relationship of the acting user to the patient when proxy access is used.',
    `session_created_timestamp` TIMESTAMP COMMENT 'Timestamp when the session record was first captured in the system.',
    `session_duration_seconds` STRING COMMENT 'Total elapsed time in seconds between login and session termination, supporting engagement and access analytics.',
    `session_expiry_timestamp` TIMESTAMP COMMENT 'Timestamp at which the session token expires and re-authentication is required.',
    `session_status` STRING COMMENT 'Current lifecycle state of the portal session.',
    `session_token` STRING COMMENT 'Opaque externally-issued session token / business key used to reference this portal session across systems.',
    `session_updated_timestamp` TIMESTAMP COMMENT 'Timestamp when the session record was last modified.',
    `termination_reason` STRING COMMENT 'The business reason the session ended, supporting security and user-experience analysis.',
    `user_agent` STRING COMMENT 'Full user-agent header captured from the client, supporting compatibility and security analytics.',
    CONSTRAINT pk_portal_session PRIMARY KEY(`portal_session_id`)
) COMMENT 'Master reference table for portal_session. Referenced by session_id.';

CREATE OR REPLACE TABLE `vibe_healthcare_v1`.`digital_health`.`secure_message_thread` (
    `secure_message_thread_id` BIGINT COMMENT 'Primary key for secure_message_thread',
    `care_site_id` BIGINT COMMENT 'Identifier of the facility or practice location that owns or routes the messaging thread within a multi-facility health system.',
    `care_team_id` BIGINT COMMENT 'Identifier of the care team the thread is routed to, enabling shared-inbox group messaging and coverage.',
    `clinician_id` BIGINT COMMENT 'Identifier of the clinician or care team member currently responsible for responding to the thread.',
    `employee_id` BIGINT COMMENT 'Identifier of the party (patient, provider, or care team member) who originated the conversation thread.',
    `mpi_record_id` BIGINT COMMENT 'Identifier of the patient who is the subject of and a participant in the secure messaging thread.',
    `visit_id` BIGINT COMMENT 'Identifier of the clinical encounter that this messaging thread is associated with or arose from, if any.',
    `parent_secure_message_thread_id` BIGINT COMMENT 'Self-referencing FK on secure_message_thread (parent_secure_message_thread_id)',
    `channel` STRING COMMENT 'The interface/channel through which the secure conversation is conducted.',
    `closed_reason` STRING COMMENT 'Categorical reason describing why the thread was closed, supporting quality and operations reporting.',
    `consent_on_file` BOOLEAN COMMENT 'Indicates whether documented patient consent for secure electronic messaging is on file, required for compliant communication.',
    `created_at` TIMESTAMP COMMENT 'Timestamp when this thread record was first captured in the source system.',
    `escalation_status` STRING COMMENT 'Current escalation state of the thread when response SLAs are at risk or breached, supporting triage workflows.',
    `first_response_at` TIMESTAMP COMMENT 'Timestamp of the first provider response, used to measure response time against patient-engagement SLAs.',
    `has_attachment` BOOLEAN COMMENT 'Indicates whether any message in the thread includes a file attachment such as a document or image.',
    `is_archived` BOOLEAN COMMENT 'Indicates whether the thread has been archived out of active inboxes while retained for compliance.',
    `is_clinical` BOOLEAN COMMENT 'Indicates whether the thread contains clinical content requiring licensed clinician review versus purely administrative content.',
    `language_code` STRING COMMENT 'ISO 639-1 language code of the conversation, supporting patient communication preferences and interpreter needs.',
    `last_message_at` TIMESTAMP COMMENT 'Timestamp of the most recent message in the thread, used for inbox sorting and stale-thread detection.',
    `message_count` STRING COMMENT 'Total number of individual messages exchanged within the thread, used for engagement and workload analytics.',
    `opened_at` TIMESTAMP COMMENT 'Timestamp when the secure conversation thread was first opened/initiated.',
    `priority` STRING COMMENT 'Clinical priority assigned to the thread, influencing response SLA and provider triage queues.',
    `requires_response` BOOLEAN COMMENT 'Flags whether an outstanding response is awaited from a provider, used for SLA monitoring and escalation.',
    `resolved_at` TIMESTAMP COMMENT 'Timestamp when the thread was marked resolved or closed by the responsible clinician.',
    `response_due_at` TIMESTAMP COMMENT 'Timestamp by which a response is required to meet the service-level commitment for the assigned priority.',
    `retention_expiry_date` DATE COMMENT 'Date when the thread becomes eligible for purge under the applicable HIPAA medical-record retention policy.',
    `sensitivity_level` STRING COMMENT 'Confidentiality sensitivity classification controlling who may view the thread (e.g., behavioral health, HIV, substance use special protections).',
    `subject_category` STRING COMMENT 'Standardized clinical or administrative topic of the thread used for routing and reporting. [ENUM-REF-CANDIDATE: medication|symptom|lab_result|referral|insurance|scheduling|general_question|test_results|care_plan — promote to reference product]',
    `thread_reference_number` STRING COMMENT 'Externally-known human-facing reference number for the conversation, surfaced in the patient portal and clinician inbox for cross-system traceability.',
    `thread_status` STRING COMMENT 'Current state of the conversation within its lifecycle, used for inbox triage and SLA tracking.',
    `thread_subject` STRING COMMENT 'Human-readable subject or title of the secure message conversation; may reference clinical context and is therefore treated as PHI under HIPAA.',
    `thread_type` STRING COMMENT 'Categorical classification segmenting threads by their primary business purpose to drive routing and analytics.',
    `unread_count` STRING COMMENT 'Number of unread messages in the thread for the currently responsible recipient, driving inbox notification badges.',
    `updated_at` TIMESTAMP COMMENT 'Timestamp when this thread record was last modified in the source system.',
    CONSTRAINT pk_secure_message_thread PRIMARY KEY(`secure_message_thread_id`)
) COMMENT 'Master reference table for secure_message_thread. Referenced by message_thread_id.';

